import boto3

# Health API only available in us-east-1
health = boto3.client('health', region_name='us-east-1')

# Describe active events for your account
paginator = health.get_paginator('describe_events')
response_iterator = paginator.paginate(
    filter={
        'eventStatusCodes': ['open', 'upcoming'],
        'eventTypeCategories': ['issue', 'scheduledChange'],
    }
)

for page in response_iterator:
    for event in page['events']:
        print(event['eventTypeCode'], event['region'], event['statusCode'])

# Get affected resources for a specific event
entities = health.describe_affected_entities(
    filter={
        'eventArns': ['arn:aws:health:us-east-1::event/EC2/AWS_EC2_INSTANCE_RETIREMENT/...'],
    }
)
for entity in entities['entities']:
    print(entity['entityValue'], entity['statusCode'])  # instance ID, status

resource "aws_sns_topic" "health_alerts" {
  name = "aws-health-alerts"
}

resource "aws_cloudwatch_event_rule" "health_events" {
  name        = "aws-health-all-events"
  description = "Route all AWS Health events to SNS"

  event_pattern = jsonencode({
    source      = ["aws.health"]
    detail-type = ["AWS Health Event"]
  })
}

resource "aws_cloudwatch_event_target" "health_sns" {
  rule      = aws_cloudwatch_event_rule.health_events.name
  target_id = "HealthSNS"
  arn       = aws_sns_topic.health_alerts.arn
}

resource "aws_sns_topic_subscription" "ops_email" {
  topic_arn = aws_sns_topic.health_alerts.arn
  protocol  = "email"
  endpoint  = "ops@example.com"
}

// FIS experiment template: simulate EC2 instance retirement
{
  "description": "Simulate retirement health event notification",
  "targets": {
    "myInstances": {
      "resourceType": "aws:ec2:instance",
      "resourceTags": { "env": "staging" },
      "selectionMode": "COUNT(1)"
    }
  },
  "actions": {
    "sendRetirementNotification": {
      "actionId": "aws:ec2:send-spot-instance-interruptions",
      "parameters": { "durationBeforeInterruption": "PT2M" },
      "targets": { "SpotInstances": "myInstances" }
    }
  },
  "stopConditions": [
    { "source": "aws:cloudwatch:alarm", "value": "arn:aws:cloudwatch:..." }
  ]
}
